import numpy as np

def tokenize_norm(s):
    s = normalize(s)
    return s.split()

def token_f1(a, b):
    ta, tb = map(set, (tokenize_norm(a), tokenize_norm(b)))
    if not ta or not tb:
        return 0.0
    overlap = len(ta & tb)
    prec = overlap / len(ta) if ta else 0
    rec = overlap / len(tb) if tb else 0
    if prec+rec == 0:
        return 0.0
    f1 = 2*prec*rec/(prec+rec)
    return f1

